/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    const n = s.length;

    // A string is "coherent" if it does not contain "011" or "110" as a subsequence.
    // Let's analyze the structure of strings that do NOT contain "011" or "110" as a subsequence.

    // Subsequence "011": requires three indices i < j < k such that s[i]='0', s[j]='1', s[k]='1'.
    // Subsequence "110": requires three indices i < j < k such that s[i]='1', s[j]='1', s[k]='0'.

    // Case 1: No "011" subsequence.
    // If we have a '0' at index i, any '1's after i must appear only once consecutively, or not at all.
    // If we have "0...1...1...", this is a "011" subsequence unless there is at most one '1' after the first '0'.
    // To avoid "011", if there is a '0', all subsequent '1's must not have two occurrences after it.
    // A simpler way to think: if a '0' appears, all '1's that follow must be preceded by another '0' or be the first '1'.
    // The structure must look like: (a block of '0's) followed by (at most one '1') followed by (rest of string). This seems too restrictive.

    // Let's look at the possible forms of a coherent string based on character groups.
    // If a string has only one type of character (e.g., "0000" or "1111"), it is coherent (no subsequence of length 3).

    // Consider a string composed of blocks of 0s and 1s.
    // Example: 00011100
    // Subsequence "011":
    // Take 0 from first block, 1 from second block, 1 from second block -> YES.
    // So, we cannot have a block of 0s followed by a block of 1s of length >= 2.
    // We cannot have a block of 1s followed by a block of 0s of length >= 2.

    // Let's re-examine the constraints imposed by "011" and "110".

    // 1. No "011": If we have a '0' at index $i$, we cannot have two '1's at indices $j, k > i$.
    //    This means that after any '0', there can be at most one '1'.
    //    Structure constraint derived from "011": A '0' must be followed by at most one '1' before any subsequent '0' or the end of the string.
    //    If we have $0 \dots 1 \dots 1$, it fails.
    //    If the string contains $0 \dots 1 \dots 0$, it is fine so far.
    //    If the string contains $0 \dots 0 \dots 1$, it is fine so far.

    // 2. No "110": If we have a '0' at index $k$, we cannot have two '1's at indices $i, j < k$.
    //    This means that before any '0', there can be at most one '1'.
    //    Structure constraint derived from "110": All '1's must appear only at the beginning, and there can be at most one '1' before the first '0'.

    // Combining these:
    // If the string contains two or more '0's, say $0_a$ and $0_b$ ($a < b$):
    //   - Constraint from $0_a$: After $0_a$, at most one '1'. If there is a second '1', $0_a \dots 1 \dots 1$ is "011".
    //   - Constraint from $0_b$: Before $0_b$, at most one '1'. If there are two '1's, $1 \dots 1 \dots 0_b$ is "110".

    // Let $N_0$ be the count of '0's, $N_1$ be the count of '1's.

    // Case $N_0 = 0$ (All '1's): "111...". Coherent. Cost = 0.
    // Case $N_1 = 0$ (All '0's): "000...". Coherent. Cost = 0.

    // Case $N_0 \ge 2$ and $N_1 \ge 2$.
    // Let $i_1, i_2$ be indices of two '0's ($i_1 < i_2$).
    // Let $j_1, j_2$ be indices of two '1's ($j_1 < j_2$).

    // If $j_1 < i_1 < i_2 < j_2$: $1_{j_1} \dots 0_{i_1} \dots 0_{i_2} \dots 1_{j_2}$. This structure doesn't immediately forbid anything.

    // Crucial observation: For a string to be coherent, it must be one of these forms:
    // 1. $00\dots01$ (All 0s followed by at most one 1).
    //    If it is $00\dots011$, then $0 \dots 1 \dots 1$ is "011". Fails.
    //    If it is $00\dots01$, it is coherent. (Max one 1).
    // 2. $100\dots0$ (At most one 1 followed by all 0s).
    //    If it is $1100\dots0$, then $1 \dots 1 \dots 0$ is "110". Fails.
    //    If it is $100\dots0$, it is coherent. (Max one 1).
    // 3. $00\dots0$ or $11\dots1$. (Coherent).

    // The only coherent strings are of the form:
    // A. All '0's: $0^k$
    // B. All '1's: $1^k$
    // C. At most one '1' followed by all '0's: $1^k 0^m$ where $k \in \{0, 1\}$. (e.g., "000", "1000")
    // D. All '0's followed by at most one '1': $0^k 1^m$ where $m \in \{0, 1\}$. (e.g., "000", "0001")

    // If a string has two or more '1's AND two or more '0's, it must fail.
    // Proof: Assume a coherent string $S$ has $N_0 \ge 2$ and $N_1 \ge 2$.
    // Let $0_1, 0_2$ be the first two zeros ($i_1 < i_2$).
    // Let $1_1, 1_2$ be the first two ones ($j_1 < j_2$).

    // Case 1: $j_1 < j_2 < i_1$. $11\dots0\dots$. $1_{j_1} 1_{j_2} 0_{i_1}$ is "110". Fails.
    // Case 2: $i_1 < i_2 < j_1 < j_2$. $0\dots0\dots11$. $0_{i_1} 1_{j_1} 1_{j_2}$ is "011". Fails.
    // Case 3: $j_1 < i_1 < j_2 < i_2$. $1\dots0\dots1\dots0$.
    //   $1_{j_1} 0_{i_1} 1_{j_2}$. No "011" or "110" yet.
    //   We need a third character. If $N_1 \ge 2$ and $N_0 \ge 2$, there are at least four indices.

    // Let's check the simplest structure that might work: $0^a 1^b$ or $1^a 0^b$ where $a, b$ are small.
    // $010$: Coherent. (No "011", no "110").
    // $101$: Coherent.

    // If a string contains $010$, it is coherent.
    // If a string contains $101$, it is coherent.

    // The set of coherent strings is characterized by the fact that the sequence of characters must be nearly monotonic.
    // Coherent strings are those that do not contain $011$ or $110$ as a subsequence.
    // This implies that the string must be of the form:
    // $0^* 1^*$ (all 0s followed by all 1s) OR $1^* 0^*$ (all 1s followed by all 0s).

    // Let's verify this strong claim:
    // 1. $0^a 1^b$: If $b \ge 2$, say $0 \dots 1 \dots 1$. This is "011" if $a \ge 1$.
    //    If $a=0$, $1^b$. Coherent.
    //    If $b=0$, $0^a$. Coherent.
    //    If $a \ge 1$ and $b \ge 2$, it contains "011". (e.g., "011")
    // 2. $1^a 0^b$: If $a \ge 2$, say $1 \dots 1 \dots 0$. This is "110" if $b \ge 1$.
    //    If $a=0$, $0^b$. Coherent.
    //    If $b=0$, $1^a$. Coherent.
    //    If $a \ge 2$ and $b \ge 1$, it contains "110". (e.g., "110")

    // Conclusion: A string $S$ is coherent if and only if:
    // 1. $S = 0^k$ (only 0s)
    // 2. $S = 1^k$ (only 1s)
    // 3. $S = 0^k 1$ (at most one 1 at the end)
    // 4. $S = 1 0^k$ (at most one 1 at the start)
    // 5. $S = 01$ (The only case where both 0s and 1s exist and the structure is $0^* 1^*$ or $1^* 0^*$ and it's coherent)

    // If $S$ is coherent, $S$ must be one of these forms:
    // Form A: $0^k$
    // Form B: $1^k$
    // Form C: $0^k 1$ (where $k \ge 1$)
    // Form D: $1 0^k$ (where $k \ge 1$)

    // Let's check the example "1010".
    // $N=4$.
    // Target forms:
    // $0^4$: "0000" (Cost: 2 flips: $1 \to 0, 1 \to 0$)
    // $1^4$: "1111" (Cost: 2 flips: $0 \to 1, 0 \to 1$)
    // $0^k 1$: "0001" (Cost: $1 \to 0, 0 \to 0, 1 \to 0, 0 \to 1$. Original: 1010. Target: 0001. Flips: $s[0]: 1\to 0$, $s[2]: 1\to 0$, $s[3]: 0\to 1$. Total 3)
    // $1 0^k$: "1000" (Cost: $s[2]: 1\to 0, s[3]: 0\to 0$. Original: 1010. Target: 1000. Flips: $s[2]: 1\to 0$. Total 1)

    // The minimum cost for "1010" is 1, matching the example.

    // The optimal strategy must be to transform $S$ into one of these canonical forms:
    // 1. All '0's ($0^N$)
    // 2. All '1's ($1^N$)
    // 3. $0^k 1$ (If $N>1$, $k=N-1$) $\implies$ Target is $0^{N-1}1$
    // 4. $1 0^k$ (If $N>1$, $k=N-1$) $\implies$ Target is $10^{N-1}$

    // Note: $0^N$ is covered by $0^N 1$ (if we allow $m=0$ for $0^k 1$) or $1 0^N$ (if we allow $k=0$ for $1 0^k$).
    // If $S = 0^N$, cost is 0.
    // If $S = 1^N$, cost is $N$.

    // Let's define the 4 target patterns based on length N:
    // T1: $0^N$
    // T2: $1^N$
    // T3: $0^{N-1}1$ (if $N \ge 1$)
    // T4: $10^{N-1}$ (if $N \ge 1$)

    // Calculate the minimum flips required to reach each target pattern.

    let minFlips = n; // Max possible flips is N

    // T1: Target is "00...0"
    let flipsT1 = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === '1') {
            flipsT1++;
        }
    }
    minFlips = Math.min(minFlips, flipsT1);

    // T2: Target is "11...1"
    let flipsT2 = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === '0') {
            flipsT2++;
        }
    }
    minFlips = Math.min(minFlips, flipsT2);

    if (n === 1) {
        // T1, T2 cover this. minFlips is already correct.
        return minFlips;
    }

    // T3: Target is "0...01" (N-1 zeros followed by one 1)
    let flipsT3 = 0;
    // Check s[0]...s[N-2] against '0'
    for (let i = 0; i < n - 1; i++) {
        if (s[i] === '1') {
            flipsT3++;
        }
    }
    // Check s[N-1] against '1'
    if (s[n - 1] === '0') {
        flipsT3++;
    }
    minFlips = Math.min(minFlips, flipsT3);

    // T4: Target is "10...0" (One 1 followed by N-1 zeros)
    let flipsT4 = 0;
    // Check s[0] against '1'
    if (s[0] === '0') {
        flipsT4++;
    }
    // Check s[1]...s[N-1] against '0'
    for (let i = 1; i < n; i++) {
        if (s[i] === '1') {
            flipsT4++;
        }
    }
    minFlips = Math.min(minFlips, flipsT4);

    return minFlips;
}

