class Solution {
    public static long solve(String s) {
        int n = s.length();
        long minFlips = n;

        // T1: Target is "00...0" (All zeros)
        long flipsT1 = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '1') {
                flipsT1++;
            }
        }
        minFlips = Math.min(minFlips, flipsT1);

        // T2: Target is "11...1" (All ones)
        long flipsT2 = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '0') {
                flipsT2++;
            }
        }
        minFlips = Math.min(minFlips, flipsT2);

        if (n == 1) {
            return minFlips;
        }

        // T3: Target is "0...01" (N-1 zeros followed by one 1)
        // This form covers 0^N if we allow the last char to be 0, but since T1 already covers 0^N,
        // we focus on the structure that maximizes the number of 0s while having at most one 1.
        // The required structures are essentially those that are monotonic or almost monotonic.
        // We test the four critical boundary structures: 0^N, 1^N, 0^{N-1}1, 10^{N-1}

        // T3: Target is "0...01"
        long flipsT3 = 0;
        // Check s[0]...s[N-2] against '0'
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) == '1') {
                flipsT3++;
            }
        }
        // Check s[N-1] against '1'
        if (s.charAt(n - 1) == '0') {
            flipsT3++;
        }
        minFlips = Math.min(minFlips, flipsT3);

        // T4: Target is "10...0" (One 1 followed by N-1 zeros)
        long flipsT4 = 0;
        // Check s[0] against '1'
        if (s.charAt(0) == '0') {
            flipsT4++;
        }
        // Check s[1]...s[N-1] against '0'
        for (int i = 1; i < n; i++) {
            if (s.charAt(i) == '1') {
                flipsT4++;
            }
        }
        minFlips = Math.min(minFlips, flipsT4);

        return minFlips;
    }
}
